VALUES
  ('heelevel3-6e2f88c7-moex-00112', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '下列何者非屬公法人？', '["新竹縣五峰鄉", "新北市新店區", "國家運動訓練中心", "國家表演藝術中心"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "28515c92bb6f", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00113', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '關於行政管轄權之敘述，下列何者正確？', '["同一事件二機關依法皆有管轄權，由受理在後之機關處理對人民較為便捷時，應由受理在後之 機關管轄", "原行政機關因組織法規變更，合併至他機關時，有關機關管轄事務變更之公告，應由原行政機 關辦理公告", "二行政機關發生管轄權爭議時，該爭議應由共同上級機關之上級機關決定之", "行政機關將其權限之一部分，委託民間團體辦理，應將其委託事項公告，並刊登政府公報或新 聞紙"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "28515c92bb6f", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00114', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '依現行法令規定，關於公務人員之任用，下列敘述何者正確？', '["曾服公務有貪污行為，經緩刑判決確定，不得任用為公務人員", "現任公務人員因犯偽造文書罪，經有罪判決並已執行完畢，不得再任公務人員", "初任各官等之試用人員，基於業務需要，經指名商調，得於試用期間調任其他職系職務", "公務人員得經依法銓敘合格而取得任用資格"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "28515c92bb6f", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00115', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '關於公務員之懲戒與懲處，下列敘述何者錯誤？', '["得為公務員之懲戒者，係懲戒法院", "得為公務員之懲處者，係公務員服務之機關", "薦任第九職等或相當九職等以下之公務員，關於其懲戒，行政首長或其主管機關首長得逕送懲 戒法院審理", "懲戒法庭就移送之懲戒案件，不得對被付懲戒人先行裁定停止職務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "28515c92bb6f", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00116', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '公務人員甲因執行公務屢有違失，年終獲乙等之考績評定，如甲欲提起行政救濟，下列敘述何者 正確？', '["甲不得對乙等考績評定提起任何救濟", "甲可依申訴、再申訴程序尋求救濟；針對再申訴決定，無法向行政法院提起行政訴訟", "甲可依申訴、再申訴程序尋求救濟；針對再申訴決定，可向行政法院提起行政訴訟", "甲可依復審程序尋求救濟；如對復審決定不服，可向行政法院提起行政訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "28515c92bb6f", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00117', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '關於命令之合法性審查，下列敘述何者正確？', '["立法院認定命令違法，得議決通知原訂定機關更正或廢止，逾期未為更正或廢止者，該命令失效", "法官對於命令無違憲審查權，自不得拒絕適用", "法官僅得審查具法規命令性質之都市計畫，對於其他法規命令均無違法審查權", "各法院就其審理之案件，對裁判上所應適用之命令，認有牴觸憲法，得聲請憲法法庭為宣告違 憲之判決 33150"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "28515c92bb6f", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00118', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '關於行政函釋與行政規則之敘述，下列何者錯誤？', '["國防部基於職權訂定執行兵役法第 43 條免除本次教育勤務點閱召集範圍基準表，其性質屬解 釋性行政規則", "主管機關就行政法規所為之釋示，係闡明法規之原意，應自法規生效之日起有其適用", "行政程序法施行前，行政機關發布之解釋性函釋，嗣後未編入由該機關編撰之法律彙編中，即 表示行政機關廢止該函釋", "性質屬於裁量基準之行政規則，應由機關首長簽署，並登載於政府公報發布之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "28515c92bb6f", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00119', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '行政機關所為下列行為，何者直接對外發生法律效力？', '["土地登記簿標示部其他登記事項欄中「本土地涉及違法地目變更，土地使用管制仍應受原『田』 地目之限制」之註記", "人民團體經核准立案後，將選任職員簡歷冊報請主管機關核備", "戶政機關以催告函通知甲辦理戶籍撤銷登記，否則將依法逕為登記", "公務人員經評定年終考績考列丙等"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "28515c92bb6f", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00120', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '教育部對於私立大學停聘其教師之核准，其法律性質為何？', '["形成私法效果之行政處分", "對人一般處分", "對物一般處分", "事實行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "28515c92bb6f", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00121', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '關於處分機關救濟期間之告知，下列敘述何者錯誤？', '["處分機關未告知救濟期間，致相對人或利害關係人遲誤者，如自處分書送達後1年內聲明不服 時，視為於法定期間內所為", "處分機關告知之救濟期間有錯誤時，應由該機關以通知更正之，並自通知送達之翌日起算法定 期間", "處分機關告知之救濟期間較法定期間為長者，處分機關雖以通知更正，如相對人或利害關係人 信賴原告知之救濟期間，致無法於法定期間內提起救濟，而於原告知之期間內為之者，視為於 法定期間內所為", "處分機關告知之救濟期間錯誤未為更正，致相對人或利害關係人遲誤者，如自處分書送達後 3 年內聲明不服時，視為於法定期間內所為"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "28515c92bb6f", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL)
